// ============================================================
//  appointment.js  —  WellSpring Family Clinic | Book Appointment
// ============================================================

// ── Utility helpers ────────────────────────────────────────

/**
 * Display a validation error beneath a form field.
 * @param {string} id  - Element ID of the error <span>
 * @param {string} msg - Error message text
 */
function setApptError(id, msg) {
  const el = document.getElementById(id);
  if (el) { el.textContent = msg; el.style.display = 'block'; }
}

/**
 * Clear all validation errors and hide success/fail banners.
 */
function clearApptErrors() {
  document.querySelectorAll('.form-error').forEach(el => {
    el.textContent   = '';
    el.style.display = 'none';
  });
  ['appt-success', 'appt-fail'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });
}

/**
 * Basic email format validation.
 * @param {string} v
 * @returns {boolean}
 */
function isEmail(v) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

/**
 * Loose phone number validation (international-friendly).
 * @param {string} v
 * @returns {boolean}
 */
function isPhone(v) {
  return /^\+?[\d\s\-()\\.]{7,15}$/.test(v);
}

/**
 * Returns true if the chosen date is today or in the past.
 * @param {string} d - ISO date string (YYYY-MM-DD)
 * @returns {boolean}
 */
function isPast(d) {
  return new Date(d) < new Date(new Date().toDateString());
}

// ── Init on DOM ready ──────────────────────────────────────

document.addEventListener('DOMContentLoaded', () => {

  // Set minimum selectable date to today
  const dateInput = document.getElementById('appt-date');
  if (dateInput) {
    dateInput.min = new Date().toISOString().split('T')[0];
  }

  // ── Form submission ──
  const form = document.getElementById('appointment-form');
  if (!form) return;

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    clearApptErrors();

    let ok = true;
    const name  = document.getElementById('appt-name').value.trim();
    const email = document.getElementById('appt-email').value.trim();
    const phone = document.getElementById('appt-phone').value.trim();
    const date  = document.getElementById('appt-date').value;

    // Validation
    if (!name)
      { setApptError('appt-name-error',  'Full name is required.');   ok = false; }
    if (!email || !isEmail(email))
      { setApptError('appt-email-error', 'Valid email required.');     ok = false; }
    if (!phone || !isPhone(phone))
      { setApptError('appt-phone-error', 'Valid phone required.');     ok = false; }
    if (!date || isPast(date))
      { setApptError('appt-date-error',  'Choose a future date.');     ok = false; }
    if (!ok) return;

    // Disable button while sending
    const btn = document.getElementById('appt-submit');
    btn.disabled    = true;
    btn.textContent = 'Sending…';

    // ── EmailJS integration ──
    // Replace 'YOUR_PUBLIC_KEY' and 'YOUR_SERVICE_ID' with your real EmailJS credentials.
    emailjs.init('YOUR_PUBLIC_KEY');
    emailjs.sendForm('YOUR_SERVICE_ID', 'template_appointment', form)
      .then(() => {
        const successEl = document.getElementById('appt-success');
        successEl.textContent  = '✅ Your appointment request has been sent! We will contact you within 24 hours to confirm.';
        successEl.style.display = 'block';

        form.reset();
        btn.disabled    = false;
        btn.textContent = 'Submit Appointment Request';
        window.scrollTo({ top: 0, behavior: 'smooth' });
      })
      .catch(() => {
        const failEl = document.getElementById('appt-fail');
        failEl.textContent  = '❌ Something went wrong. Please call us on (03) 9000 1234.';
        failEl.style.display = 'block';

        btn.disabled    = false;
        btn.textContent = 'Submit Appointment Request';
      });
  });
});
